Write comprehensive Playwright UAT tests for every admin dashboard page.

Create `tests/playwright/uat/admin-pages.spec.ts`:

For each of the 18 admin pages, verify:
1. Page loads without JavaScript errors
2. Main content area renders (not blank)
3. Data elements display (tables, cards, badges have content)
4. No 'undefined' or 'NaN' visible in text content
5. Navigation via sidebar works
6. Page-specific controls are interactive

```typescript
test.describe('Admin Dashboard UAT', () => {
  test.beforeEach(async ({ page }) => {
    await loginAsAdmin(page);
  });

  test('Dashboard Home — KPI cards visible', async ({ page }) => {
    await navigateTo(page, 'monitoring');
    await waitForData(page);
    await assertNoErrors(page);
    // Verify health cards show service count
    await expect(page.locator('[data-testid="health-card"]')).toBeVisible();
    await captureScreenshot(page, 'dashboard-home');
  });

  test('Participants — table renders with data', async ({ page }) => {
    await navigateTo(page, 'participants');
    await waitForData(page);
    await assertTableHasRows(page, 0); // may be empty but table should render
    await assertNoErrors(page);
    await captureScreenshot(page, 'participants');
  });

  // ... tests for all 18 pages
});
```

