Acceptance: All 18 page tests pass against live admin portal. Screenshots captured.

Write Playwright UAT tests that verify the bot can execute all admin actions via conversation in the real browser.

Create `tests/playwright/uat/bot-agent.spec.ts`:

```typescript
test.describe('Bot Agent UAT', () => {
  test.beforeEach(async ({ page }) => {
    await loginAsAdmin(page);
    // Open bot chat
    await page.click('[aria-label="Open GarudaX Bot"]');
    await expect(page.locator('[role="dialog"]')).toBeVisible();
  });

  async function sendBotMessage(page, message) {
    const input = page.locator('input[type="text"]').last();
    await input.fill(message);
    await input.press('Enter');
    // Wait for bot response (not typing indicator)
    await page.waitForSelector('.bot-message:last-child', { timeout: 15000 });
    return page.locator('.bot-message:last-child').textContent();
  }

  test('Bot — system health returns service list', async ({ page }) => {
    const reply = await sendBotMessage(page, 'system health');
    expect(reply).toContain('matching-engine');
    expect(reply).toContain('gateway');
    await captureScreenshot(page, 'bot-health');
  });

  test('Bot — help shows all command categories', async ({ page }) => {
    const reply = await sendBotMessage(page, 'help');
    expect(reply).toContain('Orders');
    expect(reply).toContain('Trading');
    expect(reply).toContain('Margin');
    await captureScreenshot(page, 'bot-help');
  });

  test('Bot — show instruments returns list', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show instruments');
    expect(reply).toContain('WHT-HRW');
    await captureScreenshot(page, 'bot-instruments');
  });

  test('Bot — show margin calls returns data', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show margin calls');
    expect(reply).not.toContain('error');
    expect(reply).toMatch(/active|calls|shortfall/i);
  });

  test('Bot — show participants returns data', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show participants');
    expect(reply).toContain('Participants');
  });

  test('Bot — show alerts returns data', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show alerts');
    expect(reply).toContain('Alerts');
  });

  test('Bot — ticket creation flow', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show tickets');
    expect(reply).toContain('Tickets');
  });

  test('Bot — unknown command shows suggestions', async ({ page }) => {
    const reply = await sendBotMessage(page, 'xyzzy');
    expect(reply).toContain('help');
  });

  test('Bot — wheat price returns market data', async ({ page }) => {
    const reply = await sendBotMessage(page, 'wheat price');
    // Should return ticker data or 'no data'
    expect(reply).not.toContain('error');
  });

  test('Bot — who am I returns profile', async ({ page }) => {
    const reply = await sendBotMessage(page, 'who am I');
    expect(reply).toContain('admin');
  });
});
```

Acceptance: 10+ bot UAT tests pass against live portal. Bot responds correctly to all test messages.

Write Playwright/Node tests that verify ALL gateway API endpoints return correct response shapes.

Create `tests/playwright/uat/api-contracts.spec.ts`:

For each gateway endpoint, verify:
1. Response status is 200/201 (not 500/502)
2. Response has correct Content-Type (application/json)
3. Response body has expected fields
4. Field types are correct (string/number/array/object)
5. Required fields are not null/undefined

```typescript
test.describe('API Contract UAT', () => {
  let token: string;
  const BASE = process.env.GATEWAY_URL || 'https://admin.garudax.asla.mn';

  test.beforeAll(async ({ request }) => {
    const res = await request.post(`${BASE}/api/v1/auth/login`, {
      data: { email: 'admin@garudax.mn', password: 'Adm1n@GarudaX!' }
    });
    const body = await res.json();
    token = body.AccessToken || body.access_token;
  });

  test('GET /admin/health — returns services array', async ({ request }) => {
    const res = await request.get(`${BASE}/api/v1/admin/health`, {
      headers: { Authorization: `Bearer ${token}` }
    });
    expect(res.status()).toBe(200);
    const body = await res.json();
    expect(body).toHaveProperty('overall_status');
    expect(body).toHaveProperty('services');
    expect(Array.isArray(body.services)).toBe(true);
    expect(body.services.length).toBeGreaterThan(0);
    // Each service has name + status
    for (const svc of body.services) {
      expect(svc).toHaveProperty('name');
      expect(svc).toHaveProperty('status');
    }
  });

  // Test ALL 30+ endpoints: instruments, orders, clearing, margin,
  // settlement, compliance, warehouse, risk, reports, fees, tickets, bot
});
```

